mapper.update:
UPDATE t_material_cabinet
SET deleted_flag = #{deletedFlag}
WHERE cabinet_id = #{cabinetId}

mapper.select:
SELECT *
FROM t_material_cabinet
WHERE cabinet_name = #{cabinetName}
AND deleted_flag = #{deletedFlag}
  AND enterprise_id = #{enterpriseId}

    AND cabinet_id != #{excludeCabinetId}

SELECT tc.*
FROM t_material_cabinet tc

    tc.deleted_flag = #{queryForm.deletedFlag}

        AND (INSTR(tc.cabinet_name,#{queryForm.keywords}) OR INSTR(tc.create_user_name,#{queryForm.keywords}))


        AND DATE_FORMAT(tc.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        AND DATE_FORMAT(tc.create_time, '%Y-%m-%d') <= #{queryForm.endTime}


        AND tc.enterprise_id = #{queryForm.enterpriseId}


        AND tc.disabled_flag = #{queryForm.disabledFlag}



    ORDER BY tc.create_time DESC

SELECT tc.*
FROM t_material_cabinet tc
WHERE tc.cabinet_id = #{cabinetId}
  AND tc.deleted_flag = #{deletedFlag}

SELECT *
FROM t_material_cabinet
WHERE default_flag = #{defaultFlag}
  AND deleted_flag = #{deletedFlag}
AND enterprise_id = #{enterpriseId}

    AND cabinet_id != #{excludeCabinetId}

SELECT *
FROM t_material_cabinet
WHERE deleted_flag = #{deletedFlag} AND disabled_flag = #{disabledFlag}
AND enterprise_id = #{enterpriseId}
AND trim(cabinet_name) in

    #{item}
